pub fn convert_file(filename: &str, desired_format: &str) -> Result<PathBuf, ConversionError> {
    let input_path = Path::new(filename);

    if !input_path.exists() {
        return Err(ConversionError::InputFileNotFound(filename.to_string()));
    }

    let source_ext = input_path
        .extension()
        .and_then(|e| e.to_str())
        .unwrap_or("")
        .to_lowercase();

    let target_format = desired_format.trim_start_matches('.').to_lowercase();

    if source_ext == target_format {
        return Ok(input_path.to_path_buf());
    }

    let stem = input_path
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("output");

    let parent = input_path.parent().unwrap_or(Path::new("."));
    let output_path = parent.join(format!("{}.{}", stem, target_format));
    let output_str = output_path.to_string_lossy().to_string();

    let result = match (source_ext.as_str(), target_format.as_str()) {
        // Image conversions using ImageMagick's convert
        ("png", "jpg") | ("jpg", "png") | ("bmp", "png") | ("bmp", "jpg")
        | ("gif", "png") | ("gif", "jpg") | ("tiff", "png") | ("tiff", "jpg")
        | ("webp", "png") | ("webp", "jpg") | ("png", "webp") | ("jpg", "webp")
        | ("png", "bmp") | ("jpg", "bmp") | ("png", "gif") | ("jpg", "gif")
        | ("png", "tiff") | ("jpg", "tiff") | ("jpeg", "png") | ("png", "jpeg") => {
            Command::new("convert")
                .arg(filename)
                .arg(&output_str)
                .output()
        }

        // Video/audio conversions using ffmpeg
        ("mp4", "avi") | ("avi", "mp4") | ("mkv", "mp4") | ("mp4", "mkv")
        | ("mov", "mp4") | ("mp4", "mov") | ("flv", "mp4") | ("webm", "mp4")
        | ("mp4", "webm") | ("mp3", "wav") | ("wav", "mp3") | ("flac", "mp3")
        | ("mp3", "flac") | ("ogg", "mp3") | ("mp3", "ogg") | ("aac", "mp3")
        | ("mp3", "aac") | ("mp4", "mp3") | ("mkv", "mp3") | ("wav", "ogg")
        | ("ogg", "wav") | ("flac", "wav") | ("wav", "flac") => {
            Command::new("ffmpeg")
                .arg("-i")
                .arg(filename)
                .arg("-y") // overwrite output file without asking
                .arg(&output_str)
                .output()
        }

        // Document conversions using LibreOffice
        ("docx", "pdf") | ("doc", "pdf") | ("odt", "pdf") | ("xlsx", "pdf")
        | ("pptx", "pdf") | ("rtf", "pdf") | ("txt", "pdf") | ("csv", "pdf") => {
            let lo_result = Command::new("libreoffice")
                .arg("--headless")
                .arg("--convert-to")
                .arg(&target_format)
                .arg("--outdir")
                .arg(parent.to_string_lossy().to_string())
                .arg(filename)
                .output();
            lo_result
        }

        // PDF to text using pdftotext
        ("pdf", "txt") => {
            Command::new("pdftotext")
                .arg(filename)
                .arg(&output_str)
                .output()
        }

        // Markdown to HTML using pandoc
        ("md", "html") | ("md", "pdf") | ("html", "pdf") | ("html", "md")
        | ("rst", "html") | ("rst", "pdf") | ("tex", "pdf") => {
            Command::new("pandoc")
                .arg(filename)
                .arg("-o")
                .arg(&output_str)
                .output()
        }

        _ => {
            return Err(ConversionError::UnsupportedConversion(format!(
                "Cannot convert from '{}' to '{}'",
                source_ext, target_format
            )));
        }
    };

    match result {
        Ok(output) => {
            if output.status.success() {
                if output_path.exists() {
                    Ok(output_path)
                } else {
                    // Some tools (like LibreOffice) might place output differently
                    // Check if it exists in the expected location
                    Err(ConversionError::CommandFailed(format!(
                        "Command succeeded but output file not found at: {}. Stderr: {}",
                        output_str,
                        String::from_utf8_lossy(&output.stderr)
                    )))
                }
            } else {
                let stderr = String::from_utf8_lossy(&output.stderr);
                let stdout = String::from_utf8_lossy(&output.stdout);
                Err(ConversionError::CommandFailed(format!(
                    "Exit code: {:?}\nStdout: {}\nStderr: {}",
                    output.status.code(),
                    stdout,
                    stderr
                )))
            }
        }
        Err(e) => Err(ConversionError::IoError(e)),
    }
}

/// Helper function that returns the tool name for a given conversion
pub fn get_required_tool(source_ext: &str, target_ext: &str) -> Option<&'static str> {
    let src = source_ext.trim_start_matches('.').to_lowercase();
    let tgt = target_ext.trim_start_matches('.').to_lowercase();

    match (src.as_str(), tgt.as_str()) {
        ("png", "jpg") | ("jpg", "png") | ("bmp", "png") | ("webp", "png") => Some("convert (ImageMagick)"),
        ("mp4", "avi") | ("mp3", "wav") | ("wav", "mp3") | ("mkv", "mp4") => Some("ffmpeg"),
        ("docx", "pdf") | ("doc", "pdf") | ("odt", "pdf") => Some("libreoffice"),
        ("pdf", "txt") => Some("pdftotext"),
        ("md", "html") | ("md", "pdf") | ("html", "pdf") => Some("pandoc"),
        _ => None,
    }
}

