#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;

    #[test]
    fn test_input_file_not_found() {
        let result = convert_file("nonexistent_file.png", "jpg");
        assert!(matches!(result, Err(ConversionError::InputFileNotFound(_))));
    }

    #[test]
    fn test_unsupported_conversion() {
        // Create a temporary file
        let temp_file = "test_unsupported.xyz";
        fs::write(temp_file, "test content").unwrap();

        let result = convert_file(temp_file, "abc");
        assert!(matches!(result, Err(ConversionError::UnsupportedConversion(_))));

        fs::remove_file(temp_file).unwrap();
    }

    #[test]
    fn test_same_format_returns_input() {
        let temp_file = "test_same.png";
        fs::write(temp_file, "fake png content").unwrap();

        let result = convert_file(temp_file, "png");
        assert!(result.is_ok());
        assert_eq!(result.unwrap(), PathBuf::from(temp_file));

        fs::remove_file(temp_file).unwrap();
    }

    #[test]
    fn test_get_required_tool() {
        assert_eq!(get_required_tool("png", "jpg"), Some("convert (ImageMagick)"));
        assert_eq!(get_required_tool("mp4", "avi"), Some("ffmpeg"));
        assert_eq!(get_required_tool("docx", "pdf"), Some("libreoffice"));
        assert_eq!(get_required_tool("md", "html"), Some("pandoc"));
        assert_eq!(get_required_tool("xyz", "abc"), None);
    }
}